#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=55;
int n,m,a[N][N],ans,dp[N][N][N*(N+1)/2];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	memset(dp,128,sizeof(dp));
	dp[n+1][0][0]=0;
	for(int i=1;i<=n;i++) 
	{
		for(int j=1;j<=n-i+1;j++)
		{
			cin>>a[i][j];
		}
	}
	for(int i=n;i>=1;i--)
	{
		int sum=0;
		for(int j=0;j<=n-i+1;j++)
		{
			sum+=a[j][i];
			for(int k=j;k<=m;k++)
			{
				for(int kk=max(0,j-1);kk<=n-i;kk++)
				{
					dp[i][j][k]=max(dp[i][j][k],dp[i+1][kk][k-j]+sum);
				}
//				cout<<i<<" "<<j<<" "<<k<<" "<<dp[i][j][k]<<"\n";
			}
			ans=max(ans,dp[i][j][m]);
		}
	}
	cout<<ans;
	return 0;
}
